// ─── Maintenance mode check ───
const sshRaw = $input.first().json.stdout || '';
const maintSplit = sshRaw.split('---MAINT---');
const alertsJson = (maintSplit[0] || '').trim();
const maintRaw = (maintSplit[1] || 'NONE').trim();

let maintenanceActive = false;
let maintenanceInfo = null;
if (maintRaw !== 'NONE' && maintRaw !== '') {
  try {
    maintenanceInfo = JSON.parse(maintRaw);
    maintenanceActive = true;
  } catch(e) {
    maintenanceActive = true;
    maintenanceInfo = { reason: maintRaw };
  }
}

if (maintenanceActive) {
  return [{ json: {
    hasContent: false, isRepeat: false, isAlert: false, isRecovery: false,
    isLastRecovery: false, hostname: '', ruleName: '',
    alertsB64: '', existingIssueId: '', repeatAction: 'none', shouldEscalate: false,
    flapCount: 0, isBurst: false, burstHosts: '', burstRules: '', burstSeverities: '',
    maintenanceSuppressed: true, maintenanceReason: maintenanceInfo?.reason || 'scheduled'
  }}];
}
// ─── End maintenance check ───

const webhookData = $('LibreNMS Webhook').first().json;
// sshData reconstructed from maintenance-aware SSH output split
const sshData = { stdout: alertsJson };

let body;
if (webhookData.body && typeof webhookData.body === 'object' && webhookData.body.body) {
  body = webhookData.body.body;
} else if (webhookData.body && typeof webhookData.body === 'object') {
  body = webhookData.body;
} else if (webhookData.body) {
  body = webhookData.body;
} else {
  body = webhookData;
}
if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch(e) { body = {}; }
}

// Site filter: NL receiver only processes NL hosts (nllei* prefix)
// Cross-site hosts monitored by NL LibreNMS are dropped here
const _filterHostname = body.hostname || body.sysName || '';
if (_filterHostname && !_filterHostname.startsWith('nllei')) {
  return [{ json: { hasContent: false, isRepeat: false, isAlert: false, isRecovery: false,
    isLastRecovery: false, hostname: _filterHostname, ruleName: body.title || body.rule || body.name || '',
    alertsB64: '', existingIssueId: '', repeatAction: 'none', shouldEscalate: false,
    flapCount: 0, isBurst: false, burstHosts: '', burstRules: '', burstSeverities: '',
    suppressed: true, suppressReason: 'wrong_site (non-NL host in NL receiver)' } }];
}

const sd = $getWorkflowStaticData('global');
if (!sd.activeAlerts) sd.activeAlerts = {};
if (!sd.closedHosts) sd.closedHosts = {};
if (!sd.currentBurst) sd.currentBurst = { startTime: 0, hosts: [], fired: false };

const BURST_WINDOW_MS = 300000;
const BURST_THRESHOLD = 3;
const CLOSED_COOLDOWN_MS = 300000;   // 5min (reduced from 10min)
const CREATION_LOCK_MS = 60000;
const ACTIVE_TTL_MS = 7200000;       // 2h for firing alerts
const RECOVERED_TTL_MS = 14400000;   // 4h for recovered hosts (keeps issueId for dedup)
const FLAP_ESCALATE_THRESHOLD = 2;   // escalate after 2 fire-recover cycles

// Restore from persistent file on first run
if (Object.keys(sd.activeAlerts).length === 0) {
  const sshOut = sshData.stdout || '';
  if (sshOut.trim()) {
    try {
      const loaded = JSON.parse(sshOut.trim());
      if (loaded && typeof loaded === 'object' && !Array.isArray(loaded)) {
        sd.activeAlerts = loaded;
      }
    } catch(e) {}
  }
}

// Handle registration callback from infra-triage.sh
if (body.action === 'register' && body.hostname && body.issueId) {
  const host = sd.activeAlerts[body.hostname];
  if (host) {
    host.issueId = body.issueId;
    host.registeredAt = Date.now();
    if (body.ruleName && host.rules) {
      if (!host.rules[body.ruleName]) host.rules[body.ruleName] = { firstSeen: Date.now(), count: 1 };
      host.rules[body.ruleName].lastSeen = Date.now();
    }
  } else {
    sd.activeAlerts[body.hostname] = {
      issueId: body.issueId,
      registeredAt: Date.now(),
      flapCount: 0,
      rules: { [body.ruleName || 'unknown']: { firstSeen: Date.now(), lastSeen: Date.now(), count: 1 } }
    };
  }
  const alertsB64 = Buffer.from(JSON.stringify(sd.activeAlerts)).toString('base64');
  return [{ json: { hasContent: false, isRepeat: false, isAlert: false, isRecovery: false,
    isLastRecovery: false, hostname: body.hostname, ruleName: body.ruleName || '',
    alertsB64, existingIssueId: '', repeatAction: 'none', shouldEscalate: false,
    flapCount: 0, isBurst: false, burstHosts: '', burstRules: '', burstSeverities: '' } }];
}

const hostname = body.hostname || body.sysName || '';
const ruleName = body.title || body.rule || body.name || '';
const severity = body.severity || 'unknown';
const state = typeof body.state === 'number' ? body.state : parseInt(body.state) || 0;
const timestamp = body.timestamp || new Date().toISOString();
const deviceId = body.device_id || '';

const stateMap = { 0: 'RECOVERED', 1: 'ALERT', 2: 'ACKNOWLEDGED' };
const stateLabel = stateMap[state] || 'UNKNOWN';
const isAlert = state === 1;
const isRecovery = state === 0;
const hasContent = !!(hostname && ruleName);

let isRepeat = false;
let existingIssueId = '';
let isLastRecovery = false;
let activeRuleCount = 0;
let commentText = '';
let repeatAction = 'none';
let shouldEscalate = false;
let flapCount = 0;
let isBurst = false;
let burstHosts = '';
let burstRules = '';
let burstSeverities = '';

// Burst detection: 3+ distinct hosts in 5 min
if (hasContent && isAlert) {
  const now_b = Date.now();
  if (sd.currentBurst.startTime && (now_b - sd.currentBurst.startTime > BURST_WINDOW_MS)) {
    sd.currentBurst = { startTime: 0, hosts: [], fired: false };
  }
  const alreadyInBurst = sd.currentBurst.hosts.some(h => h.hostname === hostname);
  if (!alreadyInBurst) {
    if (!sd.currentBurst.startTime) sd.currentBurst.startTime = now_b;
    sd.currentBurst.hosts.push({ hostname, ruleName, severity });
  }
  if (sd.currentBurst.hosts.length >= BURST_THRESHOLD && !sd.currentBurst.fired) {
    if (!sd.lastBurstTriggered) sd.lastBurstTriggered = 0;
    const now_burst = Date.now();
    if (now_burst - sd.lastBurstTriggered > BURST_WINDOW_MS) {
    sd.lastBurstTriggered = now_burst;
    sd.currentBurst.fired = true;
    isBurst = true;
    burstHosts = sd.currentBurst.hosts.map(h => h.hostname).join(',');
    burstRules = sd.currentBurst.hosts.map(h => h.ruleName).join(',');
    burstSeverities = sd.currentBurst.hosts.map(h => h.severity).join(',');
    }
  }
}

