if (hasContent && isAlert && sd.closedHosts[hostname]) {
  const closedAge = Date.now() - sd.closedHosts[hostname];
  if (closedAge < CLOSED_COOLDOWN_MS) {
    const minsAgo = Math.round(closedAge / 60000);
    const alertsB64 = Buffer.from(JSON.stringify(sd.activeAlerts)).toString('base64');
    return [{ json: { hostname, ruleName, severity, state, stateLabel, timestamp, deviceId,
      isAlert, isRecovery: false, hasContent: false, isRepeat: false, existingIssueId: '',
      isLastRecovery: false, activeRuleCount: 0, commentText: '', alertsB64, repeatAction: 'none',
      suppressed: true, suppressReason: 'cooldown (' + minsAgo + 'm)', shouldEscalate: false,
      flapCount: 0, isBurst: false, burstHosts: '', burstRules: '', burstSeverities: '' } }];
  } else {
    delete sd.closedHosts[hostname];
  }
}

if (hasContent && isAlert) {
  const host = sd.activeAlerts[hostname];
  if (host) {
    existingIssueId = host.issueId || '';
    if (!host.rules) host.rules = {};

    // If host was recovered, this is a flap
    if (host.recoveredAt) {
      host.flapCount = (host.flapCount || 0) + 1;
      delete host.recoveredAt;
    }
    flapCount = host.flapCount || 0;

    if (host.rules[ruleName]) {
      isRepeat = true;
      host.rules[ruleName].lastSeen = Date.now();
      host.rules[ruleName].count = (host.rules[ruleName].count || 1) + 1;
      commentText = 'Alert re-fired: ' + ruleName + ' at ' + new Date().toISOString() +
        ' (count: ' + host.rules[ruleName].count +
        (flapCount > 0 ? ', flap #' + flapCount : '') + ')';
    } else {
      isRepeat = true;
      host.rules[ruleName] = { firstSeen: Date.now(), lastSeen: Date.now(), count: 1 };
      const ruleList = Object.keys(host.rules);
      commentText = 'New alert rule triggered: ' + ruleName + ' (' + severity + ')\n' +
        'Active rules for ' + hostname + ': ' + ruleList.join(', ') +
        (flapCount > 0 ? '\nFlap count: ' + flapCount : '');
    }
    activeRuleCount = Object.keys(host.rules).length;

    // Escalate flapping hosts
    if (flapCount >= FLAP_ESCALATE_THRESHOLD) {
      shouldEscalate = true;
    }

    if (!existingIssueId) {
      if (host.firstSeen && (Date.now() - host.firstSeen < CREATION_LOCK_MS)) {
        repeatAction = 'none';
        isRepeat = false;
        const alertsB64 = Buffer.from(JSON.stringify(sd.activeAlerts)).toString('base64');
        return [{ json: { hostname, ruleName, severity, state, stateLabel, timestamp, deviceId,
