          isLastRecovery: false, activeRuleCount, commentText: '', alertsB64, repeatAction: 'none',
          suppressed: true, suppressReason: 'creation_lock', shouldEscalate: false,
          flapCount, isBurst: false, burstHosts: '', burstRules: '', burstSeverities: '' } }];
      }
      isRepeat = false;
      repeatAction = 'new';
