    } else {
      repeatAction = 'check_yt';
    }
  } else {
    sd.activeAlerts[hostname] = {
      issueId: null, firstSeen: Date.now(), flapCount: 0,
      rules: { [ruleName]: { firstSeen: Date.now(), lastSeen: Date.now(), count: 1 } }
    };
    activeRuleCount = 1;
    repeatAction = 'none';
  }
