    existingIssueId = host.issueId || '';
    flapCount = host.flapCount || 0;
    if (host.rules) {
      delete host.rules[ruleName];
      activeRuleCount = Object.keys(host.rules).length;
    }
    if (activeRuleCount === 0) {
      // All rules cleared \u2014 mark as recovered but KEEP entry
      host.recoveredAt = Date.now();

      if (flapCount === 0) {
        // First clean recovery \u2014 auto-verify
        isLastRecovery = true;
        commentText = 'All alerts cleared for ' + hostname + '. Last rule recovered: ' +
          ruleName + ' at ' + new Date().toISOString();
      } else {
        // Flapping host \u2014 don't auto-verify
        isLastRecovery = false;
        commentText = 'All alerts cleared for ' + hostname + '. Last rule recovered: ' +
          ruleName + ' at ' + new Date().toISOString() +
          ' (after ' + flapCount + ' flap(s) \u2014 keeping issue open for review)';
      }

      // Short cooldown for batch dedup
      sd.closedHosts[hostname] = Date.now();
    } else {
      const remaining = Object.keys(host.rules);
      commentText = 'Rule recovered: ' + ruleName + ' at ' + new Date().toISOString() +
        '\nStill active (' + activeRuleCount + '): ' + remaining.join(', ');
    }
  }
  // Remove from burst on recovery
  const burstIdx = sd.currentBurst.hosts.findIndex(h => h.hostname === hostname);
  if (burstIdx !== -1) sd.currentBurst.hosts.splice(burstIdx, 1);
}

