for (const h of Object.keys(sd.activeAlerts)) {
  const host = sd.activeAlerts[h];
  if (!host) { delete sd.activeAlerts[h]; continue; }

  if (host.recoveredAt) {
    // Recovered hosts: 4h TTL
    if (now - host.recoveredAt > RECOVERED_TTL_MS) {
      delete sd.activeAlerts[h];
    }
  } else if (host.rules) {
    // Active hosts: prune individual rules at 2h
    for (const r of Object.keys(host.rules)) {
      if (host.rules[r].lastSeen && (now - host.rules[r].lastSeen > ACTIVE_TTL_MS)) delete host.rules[r];
    }
    if (Object.keys(host.rules).length === 0) delete sd.activeAlerts[h];
  } else {
    delete sd.activeAlerts[h];
  }
