  repeatAction = 'reopen';
} else {
  repeatAction = 'comment';
}

const shouldEscalate = parseAlert.shouldEscalate || false;
const flapCount = parseAlert.flapCount || 0;

return [{ json: { ...parseAlert, repeatAction, ytState, shouldEscalate, flapCount } }];

