      sd.activeAlerts[hostname] = { issueId: null, firstSeen: Date.now(), flapCount: host.flapCount || 0, rules: host.rules };
    } else {
      repeatAction = 'check_yt';
    }
  } else {
    sd.activeAlerts[hostname] = {
      issueId: null, firstSeen: Date.now(), flapCount: 0,
      rules: { [ruleName]: { firstSeen: Date.now(), lastSeen: Date.now(), count: 1 } }
    };
    activeRuleCount = 1;
    repeatAction = 'none';
  }
}

// Recovery: mark rule as resolved but KEEP host entry
if (hasContent && isRecovery) {
  const host = sd.activeAlerts[hostname];
  if (host) {
    existingIssueId = host.issueId || '';
    flapCount = host.flapCount || 0;
    if (host.rules) {
      delete host.rules[ruleName];
      activeRuleCount = Object.keys(host.rules).length;
    }
    if (activeRuleCount === 0) {
      // All rules cleared \u2014 mark as recovered but KEEP entry
      host.recoveredAt = Date.now();

      if (flapCount === 0) {
        // First clean recovery \u2014 auto-verify
        isLastRecovery = true;
        commentText = 'All alerts cleared for ' + hostname + '. Last rule recovered: ' +
          ruleName + ' at ' + new Date().toISOString();
      } else {
        // Flapping host \u2014 don't auto-verify
        isLastRecovery = false;
        commentText = 'All alerts cleared for ' + hostname + '. Last rule recovered: ' +
          ruleName + ' at ' + new Date().toISOString() +
          ' (after ' + flapCount + ' flap(s) \u2014 keeping issue open for review)';
      }

      // Short cooldown for batch dedup
      sd.closedHosts[hostname] = Date.now();
    } else {
      const remaining = Object.keys(host.rules);
      commentText = 'Rule recovered: ' + ruleName + ' at ' + new Date().toISOString() +
        '\nStill active (' + activeRuleCount + '): ' + remaining.join(', ');
    }
  }
  // Remove from burst on recovery
  const burstIdx = sd.currentBurst.hosts.findIndex(h => h.hostname === hostname);
  if (burstIdx !== -1) sd.currentBurst.hosts.splice(burstIdx, 1);
}

// TTL pruning with separate thresholds
const now = Date.now();
for (const h of Object.keys(sd.activeAlerts)) {
  const host = sd.activeAlerts[h];
  if (!host) { delete sd.activeAlerts[h]; continue; }

  if (host.recoveredAt) {
    // Recovered hosts: 4h TTL
    if (now - host.recoveredAt > RECOVERED_TTL_MS) {
      delete sd.activeAlerts[h];
    }
  } else if (host.rules) {
    // Active hosts: prune individual rules at 2h
    for (const r of Object.keys(host.rules)) {
      if (host.rules[r].lastSeen && (now - host.rules[r].lastSeen > ACTIVE_TTL_MS)) delete host.rules[r];
    }
    if (Object.keys(host.rules).length === 0) delete sd.activeAlerts[h];
  } else {
    delete sd.activeAlerts[h];
  }
}
for (const h of Object.keys(sd.closedHosts)) {
  if (now - sd.closedHosts[h] > 1800000) delete sd.closedHosts[h];
}
if (sd.currentBurst.startTime && (now - sd.currentBurst.startTime > 600000)) {
  sd.currentBurst = { startTime: 0, hosts: [], fired: false };
}

// Build Matrix message with flap/escalation labels
const emojiMap = { 0: '\u2705', 1: '\ud83d\udea8', 2: '\ud83d\udc40' };
const emoji = emojiMap[state] || '\u2753';
const flapLabel = flapCount > 0 ? ' [FLAPPING x' + flapCount + ']' : '';
const escalateLabel = shouldEscalate ? ' \u2b06\ufe0f ESCALATING' : '';

const alertsB64 = Buffer.from(JSON.stringify(sd.activeAlerts)).toString('base64');

return [{ json: { hostname, ruleName, severity, state, stateLabel, timestamp, deviceId,
  isAlert, isRecovery, emoji, hasContent, isRepeat, existingIssueId, isLastRecovery,
  activeRuleCount, commentText, alertsB64, repeatAction, shouldEscalate, flapCount,
  flapLabel, escalateLabel,
  isBurst, burstHosts, burstRules, burstSeverities } }];

const parseAlert = $('Parse Alert').first().json;
const ytResponse = $input.first().json;

let repeatAction = 'comment';
let ytState = 'unknown';

try {
  const customFields = ytResponse.customFields || [];
  const stateField = customFields.find(f => f.name === 'State');
  if (stateField && stateField.value) {
    ytState = stateField.value.name || 'unknown';
  }
} catch(e) {
  ytState = 'unknown';
}

if (!ytResponse.id && !ytResponse.idReadable) {
  repeatAction = 'new';
} else if (ytState === 'Done' || ytState === 'Cancelled' || ytState === 'Duplicate') {
  repeatAction = 'new';
  const sd = $getWorkflowStaticData('global');
  if (sd.activeAlerts && sd.activeAlerts[parseAlert.hostname]) {
    sd.activeAlerts[parseAlert.hostname].issueId = null;
  }
} else if (ytState === 'To Verify') {
  repeatAction = 'reopen';
} else {
  repeatAction = 'comment';
}

const shouldEscalate = parseAlert.shouldEscalate || false;
const flapCount = parseAlert.flapCount || 0;

return [{ json: { ...parseAlert, repeatAction, ytState, shouldEscalate, flapCount } }];
